A;AACA;AAEA;AACA;IACA,8BAAA;AACA;AACA;IACA,0BAAA;AACA;AACA;IACA,sBAAA;IACA,uBAAA;IACA,SAAA;AACA;AACA","sourcesContent":["<template>\n  <section class=\"org-panel\">\n    <!-- ── Header ── -->\n    <div class=\"org-panel__header\">\n      <div class=\"org-panel__header-left\">\n        <span class=\"org-panel__avatar\">{{ initials }}</span>\n        <div>\n          <h2 class=\"org-panel__title\">{{ profile.name }}</h2>\n          <span class=\"org-panel__subtitle\">Your Organization Overview</span>\n        </div>\n      </div>\n      <div class=\"org-panel__header-right\">\n        <span class=\"org-panel__plan-badge\" :class=\"planBadgeClass\">\n          {{ subscription.planName }}\n        </span>\n        <span\n          class=\"org-panel__sub-status\"\n          :class=\"'org-panel__sub-status--' + subscription.status\"\n        >\n          {{ subscription.status }}\n        </span>\n        <button class=\"org-panel__collapse-btn\" @click=\"collapsed = !collapsed\">\n          <svg\n            xmlns=\"http://www.w3.org/2000/svg\"\n            width=\"20\"\n            height=\"20\"\n            viewBox=\"0 0 24 24\"\n            fill=\"none\"\n            stroke=\"currentColor\"\n            stroke-width=\"2\"\n            stroke-linecap=\"round\"\n            stroke-linejoin=\"round\"\n            :class=\"{ 'org-panel__chevron--rotated': collapsed }\"\n            class=\"org-panel__chevron\"\n          >\n            <polyline points=\"18 15 12 9 6 15\" />\n          </svg>\n        </button>\n      </div>\n    </div>\n\n    <div v-show=\"!collapsed\">\n      <!-- ── Summary Strip ── -->\n      <div class=\"org-panel__summary-strip\">\n        <!-- Projects -->\n        <div class=\"org-panel__stat-card\">\n          <div class=\"org-panel__stat-icon org-panel__stat-icon--blue\">\n            <svg\n              xmlns=\"http://www.w3.org/2000/svg\"\n              width=\"18\"\n              height=\"18\"\n              viewBox=\"0 0 24 24\"\n              fill=\"none\"\n              stroke=\"currentColor\"\n              stroke-width=\"2\"\n              stroke-linecap=\"round\"\n              stroke-linejoin=\"round\"\n            >\n              <rect x=\"2\" y=\"7\" width=\"20\" height=\"14\" rx=\"2\" />\n              <path d=\"M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2\" />\n            </svg>\n          </div>\n          <div>\n            <span class=\"org-panel__stat-value\"\n              >{{ usageSummary.projectCount\n              }}<span class=\"org-panel__stat-max\"\n                >/{{ subscription.maxProjects }}</span\n              ></span\n            >\n            <span class=\"org-panel__stat-label\">Projects</span>\n            <div class=\"org-panel__usage-bar\">\n              <div\n                class=\"org-panel__usage-fill\"\n                :style=\"\n                  usageFillStyle(\n                    usageSummary.projectCount,\n                    subscription.maxProjects,\n                  )\n                \"\n                :class=\"\n                  usageFillClass(\n                    usageSummary.projectCount,\n                    subscription.maxProjects,\n                  )\n                \"\n              ></div>\n            </div>\n          </div>\n        </div>\n\n        <!-- Members -->\n        <div class=\"org-panel__stat-card\">\n          <div class=\"org-panel__stat-icon org-panel__stat-icon--green\">\n            <svg\n              xmlns=\"http://www.w3.org/2000/svg\"\n              width=\"18\"\n              height=\"18\"\n              viewBox=\"0 0 24 24\"\n              fill=\"none\"\n              stroke=\"currentColor\"\n              stroke-width=\"2\"\n              stroke-linecap=\"round\"\n              stroke-linejoin=\"round\"\n            >\n              <path d=\"M17 21v-2a4 4 0 0 0-4-4H5a4 4 0 0 0-4 4v2\" />\n              <circle cx=\"9\" cy=\"7\" r=\"4\" />\n              <path d=\"M23 21v-2a4 4 0 0 0-3-3.87\" />\n              <path d=\"M16 3.13a4 4 0 0 1 0 7.75\" />\n            </svg>\n          </div>\n          <div>\n            <span class=\"org-panel__stat-value\"\n              >{{ usageSummary.memberCount\n              }}<span class=\"org-panel__stat-max\"\n                >/{{ subscription.maxMembers }}</span\n              ></span\n            >\n            <span class=\"org-panel__stat-label\">Members</span>\n            <div class=\"org-panel__usage-bar\">\n              <div\n                class=\"org-panel__usage-fill\"\n                :style=\"\n                  usageFillStyle(\n                    usageSummary.memberCount,\n                    subscription.maxMembers,\n                  )\n                \"\n                :class=\"\n                  usageFillClass(\n                    usageSummary.memberCount,\n                    subscription.maxMembers,\n                  )\n                \"\n              ></div>\n            </div>\n          </div>\n        </div>\n\n        <!-- Tasks -->\n        <div class=\"org-panel__stat-card\">\n          <div class=\"org-panel__stat-icon org-panel__stat-icon--purple\">\n            <svg\n              xmlns=\"http://www.w3.org/2000/svg\"\n              width=\"18\"\n              height=\"18\"\n              viewBox=\"0 0 24 24\"\n              fill=\"none\"\n              stroke=\"currentColor\"\n              stroke-width=\"2\"\n              stroke-linecap=\"round\"\n              stroke-linejoin=\"round\"\n            >\n              <polyline points=\"9 11 12 14 22 4\" />\n              <path\n                d=\"M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11\"\n              />\n            </svg>\n          </div>\n          <div>\n            <span class=\"org-panel__stat-value\"\n              >{{ usageSummary.doneTasks\n              }}<span class=\"org-panel__stat-max\"\n                >/{{ usageSummary.totalTasks }}</span\n              ></span\n            >\n            <span class=\"org-panel__stat-label\">Tasks Done</span>\n            <div class=\"org-panel__usage-bar\">\n              <div\n                class=\"org-panel__usage-fill org-panel__usage-fill--ok\"\n                :style=\"\n                  usageFillStyle(\n                    usageSummary.doneTasks,\n                    usageSummary.totalTasks,\n                  )\n                \"\n              ></div>\n            </div>\n          </div>\n        </div>\n\n        <!-- Plan / Billing -->\n        <div class=\"org-panel__stat-card\">\n          <div class=\"org-panel__stat-icon org-panel__stat-icon--orange\">\n            <svg\n              xmlns=\"http://www.w3.org/2000/svg\"\n              width=\"18\"\n              height=\"18\"\n              viewBox=\"0 0 24 24\"\n              fill=\"none\"\n              stroke=\"currentColor\"\n              stroke-width=\"2\"\n              stroke-linecap=\"round\"\n              stroke-linejoin=\"round\"\n            >\n              <rect x=\"1\" y=\"4\" width=\"22\" height=\"16\" rx=\"2\" ry=\"2\" />\n              <line x1=\"1\" y1=\"10\" x2=\"23\" y2=\"10\" />\n            </svg>\n          </div>\n          <div>\n            <span class=\"org-panel__stat-value\">{{\n              subscription.price > 0\n                ? \"€\" + subscription.price.toFixed(2)\n                : \"Free\"\n            }}</span>\n            <span class=\"org-panel__stat-label\">{{\n              subscription.price > 0 ? \"per month\" : \"Current Plan\"\n            }}</span>\n            <span class=\"org-panel__stat-sub\">{{\n              subscription.price > 0\n                ? \"€\" + (subscription.price * 12).toFixed(2) + \"/yr\"\n                : \"Upgrade available\"\n            }}</span>\n          </div>\n        </div>\n\n        <!-- Storage -->\n        <div class=\"org-panel__stat-card\">\n          <div class=\"org-panel__stat-icon org-panel__stat-icon--teal\">\n            <svg\n              xmlns=\"http://www.w3.org/2000/svg\"\n              width=\"18\"\n              height=\"18\"\n              viewBox=\"0 0 24 24\"\n              fill=\"none\"\n              stroke=\"currentColor\"\n              stroke-width=\"2\"\n              stroke-linecap=\"round\"\n              stroke-linejoin=\"round\"\n            >\n              <ellipse cx=\"12\" cy=\"5\" rx=\"9\" ry=\"3\" />\n              <path d=\"M21 12c0 1.66-4 3-9 3s-9-1.34-9-3\" />\n              <path d=\"M3 5v14c0 1.66 4 3 9 3s9-1.34 9-3V5\" />\n            </svg>\n          </div>\n          <div>\n            <span class=\"org-panel__stat-value\"\n              >{{ subscription.sharedStorageGb }} GB</span\n            >\n            <span class=\"org-panel__stat-label\">Shared / project</span>\n            <span class=\"org-panel__stat-sub\"\n              >{{ subscription.privateStorageGb }} GB private/user</span\n            >\n          </div>\n        </div>\n      </div>\n\n      <!-- ── Bottom Grid: Projects + Members + Plan Details ── -->\n      <div class=\"org-panel__grid\">\n        <!-- Projects List -->\n        <div class=\"org-panel__card org-panel__card--projects\">\n          <h3 class=\"org-panel__card-title\">Projects</h3>\n          <div class=\"org-panel__card-underline\"></div>\n\n          <div v-if=\"projects.length === 0\" class=\"org-panel__empty\">\n            No projects yet.\n          </div>\n\n          <div\n            v-for=\"project in projects\"\n            :key=\"'proj-' + project.id\"\n            class=\"org-panel__project-row\"\n            @click=\"toggleProject(project.id)\"\n          >\n            <div class=\"org-panel__project-main\">\n              <div class=\"org-panel__project-info\">\n                <span class=\"org-panel__project-name\">{{ project.name }}</span>\n                <span class=\"org-panel__project-meta\">\n                  {{ project.done }}/{{ project.total }} tasks done\n                  <span\n                    v-if=\"project.overdue > 0\"\n                    class=\"org-panel__overdue-badge\"\n                    >{{ project.overdue }} overdue</span\n                  >\n                </span>\n              </div>\n              <div class=\"org-panel__project-right\">\n                <span class=\"org-panel__progress-label\"\n                  >{{ project.progress }}%</span\n                >\n                <svg\n                  xmlns=\"http://www.w3.org/2000/svg\"\n                  width=\"14\"\n                  height=\"14\"\n                  viewBox=\"0 0 24 24\"\n                  fill=\"none\"\n                  stroke=\"currentColor\"\n                  stroke-width=\"2\"\n                  stroke-linecap=\"round\"\n                  stroke-linejoin=\"round\"\n                  :class=\"{\n                    'org-panel__row-chevron--open':\n                      expandedProjects[project.id],\n                  }\"\n                  class=\"org-panel__row-chevron\"\n                >\n                  <polyline points=\"6 9 12 15 18 9\" />\n                </svg>\n              </div>\n            </div>\n\n            <!-- Progress bar -->\n            <div class=\"org-panel__proj-bar\">\n              <div\n                class=\"org-panel__proj-fill\"\n                :style=\"{ width: project.progress + '%' }\"\n                :class=\"progressClass(project.progress)\"\n              ></div>\n            </div>\n\n            <!-- Expandable stacks breakdown -->\n            <div\n              v-if=\"expandedProjects[project.id] && project.stacks.length\"\n              class=\"org-panel__stacks\"\n            >\n              <div\n                v-for=\"(stack, si) in project.stacks\"\n                :key=\"'stack-' + si\"\n                class=\"org-panel__stack-chip\"\n              >\n                <span class=\"org-panel__stack-name\">{{ stack.title }}</span>\n                <span class=\"org-panel__stack-count\">{{ stack.count }}</span>\n              </div>\n            </div>\n          </div>\n        </div>\n\n        <!-- Members List -->\n        <div class=\"org-panel__card\">\n          <h3 class=\"org-panel__card-title\">Members</h3>\n          <div class=\"org-panel__card-underline\"></div>\n\n          <div v-if=\"members.length === 0\" class=\"org-panel__empty\">\n            No members yet.\n          </div>\n\n          <div\n            v-for=\"member in members\"\n            :key=\"'mem-' + member.userId\"\n            class=\"org-panel__member-row\"\n          >\n            <span class=\"org-panel__member-avatar\">{{\n              member.userId.charAt(0).toUpperCase()\n            }}</span>\n            <div class=\"org-panel__member-info\">\n              <span class=\"org-panel__member-name\">{{ member.userId }}</span>\n              <span\n                class=\"org-panel__member-role\"\n                :class=\"'org-panel__member-role--' + member.role\"\n                >{{ member.role }}</span\n              >\n            </div>\n          </div>\n        </div>\n\n        <!-- Plan Details -->\n        <div class=\"org-panel__card\">\n          <h3 class=\"org-panel__card-title\">Plan Details</h3>\n          <div class=\"org-panel__card-underline\"></div>\n\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Plan</span>\n            <span class=\"org-panel__plan-badge\" :class=\"planBadgeClass\">{{\n              subscription.planName\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Price</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              subscription.price > 0\n                ? \"€\" + subscription.price.toFixed(2) + \"/mo\"\n                : \"Free\"\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Status</span>\n            <span\n              class=\"org-panel__sub-status\"\n              :class=\"'org-panel__sub-status--' + subscription.status\"\n              >{{ subscription.status }}</span\n            >\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Visibility</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              subscription.isPublic ? \"Public\" : \"Private\"\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Max Projects</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              subscription.maxProjects\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Max Members</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              subscription.maxMembers\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Shared Storage</span>\n            <span class=\"org-panel__plan-detail-value\"\n              >{{ subscription.sharedStorageGb }} GB / project</span\n            >\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Private Storage</span>\n            <span class=\"org-panel__plan-detail-value\"\n              >{{ subscription.privateStorageGb }} GB / user</span\n            >\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Started</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              formatDate(subscription.startedAt)\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Expires</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              subscription.endedAt\n                ? formatDate(subscription.endedAt)\n                : \"No expiry\"\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Contact</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              profile.contactEmail\n            }}</span>\n          </div>\n          <div class=\"org-panel__plan-detail-row\">\n            <span class=\"org-panel__plan-detail-label\">Admin User</span>\n            <span class=\"org-panel__plan-detail-value\">{{\n              profile.adminUid\n            }}</span>\n          </div>\n        </div>\n      </div>\n    </div>\n  </section>\n</template>\n\n<script>\nexport default {\n  name: \"OrgOverviewPanel\",\n  props: {\n    orgOverview: {\n      type: Object,\n      required: true,\n    },\n  },\n  data: function () {\n    return {\n      collapsed: false,\n      expandedProjects: {},\n    };\n  },\n  computed: {\n    profile: function () {\n      return (\n        this.orgOverview.profile || {\n          name: \"—\",\n          contactEmail: \"—\",\n          adminUid: \"—\",\n        }\n      );\n    },\n    subscription: function () {\n      return (\n        this.orgOverview.subscription || {\n          status: \"none\",\n          planName: \"No plan\",\n          price: 0,\n          maxProjects: 0,\n          maxMembers: 0,\n          sharedStorageGb: 0,\n          privateStorageGb: 0,\n          startedAt: null,\n          endedAt: null,\n          isPublic: false,\n        }\n      );\n    },\n    members: function () {\n      return this.orgOverview.members || [];\n    },\n    projects: function () {\n      return this.orgOverview.projects || [];\n    },\n    usageSummary: function () {\n      return (\n        this.orgOverv